const fm = FileManager.iCloud()

function dataRootPath() {
  return fm.joinPath(fm.documentsDirectory(), APP_DATA_DIR)
}

function filePath(fileName) {
  return fm.joinPath(dataRootPath(), fileName)
}

function medicationsDirPath() {
  return filePath(CATEGORY_DIR)
}

function historyDirPath() {
  return filePath(HISTORY_DIR)
}

function exportDirPath() {
  return filePath(EXPORT_DIR)
}

function categoryFilePath(fileName) {
  return fm.joinPath(medicationsDirPath(), fileName)
}

function historyFilePath(fileName) {
  return fm.joinPath(historyDirPath(), fileName)
}

function normalizeCategoryName(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_-]+/g, "_")
    .replace(/^_+|_+$/g, "")
}

function makeCategoryFileName(category) {
  const safe = normalizeCategoryName(category) || DEFAULT_CATEGORY
  return `${safe}${CATEGORY_FILE_SUFFIX}`
}

function categoryFromFileName(fileName) {
  const match = /^([a-z0-9_-]+)\.json$/i.exec(fileName)
  if (match) return normalizeCategoryName(match[1]) || DEFAULT_CATEGORY
  const fallback = fileName.replace(/\.json$/i, "")
  return normalizeCategoryName(fallback) || DEFAULT_CATEGORY
}

function makeCompoundId(category, baseKey) {
  return `${normalizeCategoryName(category) || DEFAULT_CATEGORY}::${baseKey}`
}

function splitCompoundId(value) {
  const parts = String(value || "").split("::")
  if (parts.length !== 2) return null
  return { category: parts[0], base_key: parts[1] }
}

// ---------- General helpers ----------
function toNumber(value, fallback) {
  const n = Number(value)
  return Number.isFinite(n) ? n : fallback
}

function isObject(value) {
  return value != null && typeof value === "object" && !Array.isArray(value)
}

function titleCase(s) {
  if (!s) return ""
  return String(s)
    .replace(/[_-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b\w/g, function(c) { return c.toUpperCase() })
}

function iso(value) {
  const d = value instanceof Date ? value : new Date(value)
  if (isNaN(d.getTime())) throw new Error("Invalid date value")
  return d.toISOString()
}

function dt(value) {
  return new Date(value)
}

function isValidDate(value) {
  return value instanceof Date && !isNaN(value.getTime())
}

function daysBetween(a, b) {
  return (b.getTime() - a.getTime()) / 86400000
}

function formatDateTime(d) {
  const df = new DateFormatter()
  df.useMediumDateStyle()
  df.useShortTimeStyle()
  return df.string(d)
}

function formatShortDateTime(d) {
  const df = new DateFormatter()
  df.dateFormat = "MMM d, HH:mm"
  return df.string(d)
}

function formatRelativeTime(target, now) {
  const diffMs = target.getTime() - now.getTime()
  const hours = Math.round(diffMs / 3600000)
  if (Math.abs(hours) < 36) {
    return hours >= 0 ? `in ${hours}h` : `${Math.abs(hours)}h ago`
  }
  const days = Math.round(diffMs / 86400000)
  return days >= 0 ? `in ${days}d` : `${Math.abs(days)}d ago`
}

function safeErrorMessage(error) {
  if (!error) return "Unknown error"
  if (typeof error === "string") return error
  if (error instanceof Error && error.message) return error.message
  return String(error)
}

function normalizeText(value) {
  return String(value || "").trim()
}

function cleanObject(value) {
  return isObject(value) ? value : {}
}

function parseShortcutInput() {
  const q = args.queryParameters || {}
  if (q.action) return q

  const p = args.shortcutParameter
  if (!p) return null
  if (typeof p === "string") {
    try {
      return JSON.parse(p)
    } catch (error) {
      return { action: p }
    }
  }
  return p
}

function makeId(prefix) {
  const rand = Math.random().toString(36).slice(2, 10)
  return `${prefix}_${Date.now()}_${rand}`
}

// ---------- Schema + storage ----------
function buildStarterMedicationData(category) {
  const normalizedCategory = normalizeCategoryName(category) || DEFAULT_CATEGORY
  const compounds = STARTER_MEDICATION_LIBRARY[normalizedCategory] || STARTER_MEDICATION_LIBRARY[DEFAULT_CATEGORY]
  return {
    schema_version: SCHEMA_VERSION,
    category: normalizedCategory,
    compounds: JSON.parse(JSON.stringify(compounds))
  }
}

function buildStarterHistoryData(category) {
  const normalizedCategory = normalizeCategoryName(category) || DEFAULT_CATEGORY
  const starter = STARTER_HISTORY_LIBRARY[normalizedCategory] || { injections: [], protocols: [] }
  return {
    schema_version: SCHEMA_VERSION,
    category: normalizedCategory,
    injections: JSON.parse(JSON.stringify(starter.injections || [])),
    protocols: JSON.parse(JSON.stringify(starter.protocols || []))
  }
}

function listCategoryFilesInDir(dirPath) {
  if (!fm.fileExists(dirPath)) return []
  const names = fm.listContents(dirPath)
  const files = names.filter(function(name) {
    return /^[a-z0-9_-]+\.json$/i.test(name)
  })
  files.sort()
  return files
}

function readJson(pathValue) {
  const rawText = fm.readString(pathValue)
  try {
    return JSON.parse(rawText)
  } catch (error) {
    throw new Error(`Data file is not valid JSON: ${pathValue}`)
  }
}

function writeJson(pathValue, value) {
  fm.writeString(pathValue, JSON.stringify(value, null, 2))
}

async function ensureDataFiles() {
  if (!fm.fileExists(dataRootPath())) {
    fm.createDirectory(dataRootPath(), true)
  }

  if (!fm.fileExists(medicationsDirPath())) {
    fm.createDirectory(medicationsDirPath(), true)
  }
  if (!fm.fileExists(historyDirPath())) {
    fm.createDirectory(historyDirPath(), true)
  }
  if (!fm.fileExists(exportDirPath())) {
    fm.createDirectory(exportDirPath(), true)
  }

  const starterCategories = Object.keys(STARTER_MEDICATION_LIBRARY)
  const medicationFiles = listCategoryFilesInDir(medicationsDirPath())
  const historyFiles = listCategoryFilesInDir(historyDirPath())
  const existingMedication = {}
  const existingHistory = {}

  medicationFiles.forEach(function(fileName) {
    existingMedication[categoryFromFileName(fileName)] = true
  })
  historyFiles.forEach(function(fileName) {
    existingHistory[categoryFromFileName(fileName)] = true
  })

  for (const category of starterCategories) {
    if (!existingMedication[category]) {
      writeJson(categoryFilePath(makeCategoryFileName(category)), buildStarterMedicationData(category))
    }
    if (!existingHistory[category]) {
      writeJson(historyFilePath(makeCategoryFileName(category)), buildStarterHistoryData(category))
    }
  }
}

    function normalizeQuality(value) {
      const q = String(value || "rough").toLowerCase()
      if (q === "good" || q === "rough" || q === "low") return q
      return "rough"
    }

    function normalizeCompound(name, c, index) {
      const compound = cleanObject(c)
      const references = Array.isArray(compound.references)
        ? compound.references.map(function(value) { return normalizeText(value) }).filter(Boolean)
        : []
      const provenance = normalizeText(compound.provenance)
      const notes = normalizeText(compound.notes)
      return {
        display_name: compound.display_name || titleCase(name),
        half_life_days: Math.max(0.001, toNumber(compound.half_life_days, 1)),
        bioavailability: Math.max(0, toNumber(compound.bioavailability, 1)),
        vd_l: Math.max(0.001, toNumber(compound.vd_l, 10)),
        route: compound.route || "unknown",
        model_quality: normalizeQuality(compound.model_quality),
        color: compound.color || COLOR_PALETTE[index % COLOR_PALETTE.length],
        notes: notes,
        provenance: provenance || (notes ? "Custom notes" : "Unspecified"),
        references: references
      }
    }

    function normalizeMedicationData(rawData, fallbackCategory) {
      const data = isObject(rawData) ? rawData : {}
      const category = normalizeCategoryName(data.category || fallbackCategory) || DEFAULT_CATEGORY
      const compoundsInput = isObject(data.compounds) ? data.compounds : {}
      const compounds = {}
      const names = Object.keys(compoundsInput)

      for (let i = 0; i < names.length; i++) {
        const name = names[i]
        compounds[name] = normalizeCompound(name, compoundsInput[name], i)
      }

      return {
        schema_version: SCHEMA_VERSION,
        category: category,
        compounds: compounds
      }
    }

    function validateMedicationData(data) {
      const warnings = []
      const names = Object.keys(data.compounds || {})
      const seenDisplayNames = {}

      for (const name of names) {
        const compound = data.compounds[name]
        if (!compound) continue
        if (compound.half_life_days <= 0) warnings.push(`Compound ${name} has an invalid half-life`)
        if (compound.vd_l <= 0) warnings.push(`Compound ${name} has an invalid volume of distribution`)

        const displayKey = normalizeText(compound.display_name).toLowerCase()
        if (displayKey) {
          if (seenDisplayNames[displayKey]) warnings.push(`Duplicate display name detected: ${compound.display_name}`)
          seenDisplayNames[displayKey] = true
        }
      }

      return warnings
    }

    function normalizeInjectionRecord(injection) {
      if (!isObject(injection)) return null
      const compound = String(injection.compound || "").trim()
      if (!compound) return null

      const dose = toNumber(injection.dose_mg != null ? injection.dose_mg : injection.dose, NaN)
      const time = new Date(injection.time)
      if (!Number.isFinite(dose) || dose <= 0 || !isValidDate(time)) return null

      return {
        id: injection.id || makeId("inj"),
        compound: compound,
        dose_mg: dose,
        time: iso(time),
        source: injection.source || "log",
        notes: injection.notes || ""
      }
    }

    function normalizeProtocolRecord(protocol) {
      if (!isObject(protocol)) return null
      const compound = String(protocol.compound || "").trim()
      if (!compound) return null

      const start = new Date(protocol.start)
      const dose = toNumber(protocol.dose_mg != null ? protocol.dose_mg : protocol.dose, NaN)
      const everyDays = toNumber(protocol.every_days, 7)
      const occurrences = protocol.occurrences == null || protocol.occurrences === ""
        ? null
        : toNumber(protocol.occurrences, null)
      const until = protocol.until ? new Date(protocol.until) : null

      if (!isValidDate(start) || !Number.isFinite(dose) || dose <= 0 || !Number.isFinite(everyDays) || everyDays <= 0) {
        return null
      }

      return {
        id: protocol.id || makeId("pro"),
        compound: compound,
        start: iso(start),
        dose_mg: dose,
        every_days: everyDays,
        occurrences: Number.isFinite(occurrences) ? Math.max(0, Math.floor(occurrences)) : null,
        until: until && isValidDate(until) ? iso(until) : null,
        enabled: protocol.enabled !== false,
        notes: protocol.notes || ""
      }
    }

    function normalizeHistoryData(rawData, fallbackCategory) {
      const data = isObject(rawData) ? rawData : {}
      const category = normalizeCategoryName(data.category || fallbackCategory) || DEFAULT_CATEGORY
      const injectionsInput = Array.isArray(data.injections) ? data.injections : []
      const protocolsInput = Array.isArray(data.protocols) ? data.protocols : []

      const injections = injectionsInput
        .map(function(injection) { return normalizeInjectionRecord(injection) })
        .filter(Boolean)
        .sort(function(a, b) { return dt(a.time) - dt(b.time) })

      const protocols = protocolsInput
        .map(function(protocol) { return normalizeProtocolRecord(protocol) })
        .filter(Boolean)
        .sort(function(a, b) { return dt(a.start) - dt(b.start) })

      return {
        schema_version: SCHEMA_VERSION,
        category: category,
        injections: injections,
        protocols: protocols
      }
    }

    function saveMedicationFile(fileName, data) {
      const normalized = normalizeMedicationData(data, categoryFromFileName(fileName))
      writeJson(categoryFilePath(fileName), normalized)
    }

    function saveHistoryFile(fileName, data) {
      const normalized = normalizeHistoryData(data, categoryFromFileName(fileName))
      writeJson(historyFilePath(fileName), normalized)
    }

    async function loadMedicationFile(fileName) {
      const p = categoryFilePath(fileName)
      await fm.downloadFileFromiCloud(p)
      return normalizeMedicationData(readJson(p), categoryFromFileName(fileName))
    }

    async function loadHistoryFile(fileName) {
      const p = historyFilePath(fileName)
      if (!fm.fileExists(p)) {
        const starter = buildStarterHistoryData(categoryFromFileName(fileName))
        saveHistoryFile(fileName, starter)
      }

      await fm.downloadFileFromiCloud(p)
      return normalizeHistoryData(readJson(p), categoryFromFileName(fileName))
    }

    async function loadData() {
      await ensureDataFiles()

      const medicationFiles = listCategoryFilesInDir(medicationsDirPath())

      const merged = {
        schema_version: SCHEMA_VERSION,
        compounds: {},
        injections: [],
        protocols: [],
        categories: [],
        __files: {},
        __diagnostics: {
          warnings: []
        }
      }
      for (const fileName of medicationFiles) {
        const medicationData = await loadMedicationFile(fileName)

        const historyData = await loadHistoryFile(fileName)
        const category = normalizeCategoryName(medicationData.category || historyData.category || categoryFromFileName(fileName)) || DEFAULT_CATEGORY

        merged.__files[fileName] = {
          category: category,
          compounds: medicationData.compounds,
          history: historyData
        }
        merged.categories.push(category)

        const baseNames = Object.keys(medicationData.compounds)
        for (const baseName of baseNames) {
          const compoundId = makeCompoundId(category, baseName)
          const c = medicationData.compounds[baseName]
          merged.compounds[compoundId] = {
            display_name: c.display_name,
            half_life_days: c.half_life_days,
            bioavailability: c.bioavailability,
            vd_l: c.vd_l,
            route: c.route,
            model_quality: c.model_quality,
            color: c.color,
            notes: c.notes || "",
            provenance: c.provenance || "Unspecified",
            references: Array.isArray(c.references) ? c.references.slice() : [],
            category: category,
            base_key: baseName,
            source_file: fileName
          }
        }

        merged.__diagnostics.warnings = merged.__diagnostics.warnings.concat(validateMedicationData(medicationData))

        for (const injection of historyData.injections) {
          const compoundId = makeCompoundId(category, injection.compound)
          const resolvedCompound = merged.compounds[compoundId]
          if (!resolvedCompound) {
            merged.__diagnostics.warnings.push(`Unknown injection compound ${injection.compound} in ${fileName}`)
            continue
          }
          merged.injections.push({
            id: injection.id,
            compound: compoundId,
            dose_mg: injection.dose_mg,
            time: injection.time,
            source: injection.source,
            notes: injection.notes || "",
            category: resolvedCompound.category,
            source_file: resolvedCompound.source_file
          })
        }

        for (const protocol of historyData.protocols) {
          const compoundId = makeCompoundId(category, protocol.compound)
          const resolvedCompound = merged.compounds[compoundId]
          if (!resolvedCompound) {
            merged.__diagnostics.warnings.push(`Unknown schedule compound ${protocol.compound} in ${fileName}`)
            continue
          }
          merged.protocols.push({
            id: protocol.id,
            compound: compoundId,
            start: protocol.start,
            dose_mg: protocol.dose_mg,
            every_days: protocol.every_days,
            occurrences: protocol.occurrences,
            until: protocol.until,
            enabled: protocol.enabled,
            notes: protocol.notes || "",
            category: resolvedCompound.category,
            source_file: resolvedCompound.source_file
          })
        }
      }

      merged.categories = Array.from(new Set(merged.categories)).sort()
      merged.injections.sort(function(a, b) { return dt(a.time) - dt(b.time) })
      merged.protocols.sort(function(a, b) { return dt(a.start) - dt(b.start) })
      merged.__diagnostics.warnings = Array.from(new Set(merged.__diagnostics.warnings))

      return merged
    }

// ---------- Compound + event model ----------
    function compoundNames(data) {
      return Object.keys(data.compounds)
    }

    function activeCompoundNames(data) {
      const seen = {}
      for (const injection of data.injections) seen[injection.compound] = true
      for (const protocol of data.protocols) {
        if (protocol.enabled !== false) seen[protocol.compound] = true
      }
      const names = Object.keys(seen)
      return names.length ? names : compoundNames(data)
    }

    function normalizeCompoundKey(data, value, category) {
      if (!value) return null
      const needle = String(value).trim().toLowerCase()
      const wantedCategory = normalizeCategoryName(category || "")
      if (!needle) return null

      const names = compoundNames(data)
      for (const name of names) {
        if (name.toLowerCase() === needle) return name
      }

      if (wantedCategory && needle.indexOf("::") === -1) {
        const candidate = makeCompoundId(wantedCategory, normalizeCategoryName(needle))
        if (data.compounds[candidate]) return candidate
      }

      return null
    }

    function eventAmountAtTime(event, t, compound) {
      const eventTime = dt(event.time)
      if (!isValidDate(eventTime) || eventTime > t) return 0
      const halfLifeDays = Math.max(0.001, toNumber(compound.half_life_days, 1))
      const elimination = Math.log(2) / halfLifeDays
      const dose = toNumber(event.dose_mg, 0)
      const f = Math.max(0, toNumber(compound.bioavailability, 1))
      const ageDays = daysBetween(eventTime, t)
      return dose * f * Math.exp(-elimination * ageDays)
    }

    function loggedEventsForCompound(data, compoundName, fromTime, toTime) {
      return data.injections
        .filter(function(injection) {
          if (injection.compound !== compoundName) return false
          const at = dt(injection.time)
          if (!isValidDate(at)) return false
          if (fromTime && at < fromTime) return false
          if (toTime && at > toTime) return false
          return toNumber(injection.dose_mg, 0) > 0
        })
        .map(function(injection) {
          return {
            compound: compoundName,
            dose_mg: toNumber(injection.dose_mg, 0),
            time: injection.time,
            source: "log"
          }
        })
    }

    function generateProtocolEvents(data, compoundName, fromTime, toTime, options) {
      const events = []
      const now = new Date()
      const includePast = options && typeof options.includePast === "boolean" ? options.includePast : true
      const includeFuture = options && typeof options.includeFuture === "boolean" ? options.includeFuture : true
      let globalCount = 0

      for (const protocol of data.protocols) {
        if (globalCount >= MAX_PROTOCOL_EVENTS) break
        if (protocol.enabled === false || protocol.compound !== compoundName) continue

        const start = dt(protocol.start)
        const stepDays = Math.max(0.25, toNumber(protocol.every_days, 7))
        const stepMs = stepDays * 86400000
        const dose = toNumber(protocol.dose_mg, 0)
        const occurrences = protocol.occurrences != null ? Math.max(0, toNumber(protocol.occurrences, 0)) : null
        const until = protocol.until ? dt(protocol.until) : null

        if (!isValidDate(start) || !(dose > 0)) continue

        const windowStart = isValidDate(fromTime) ? fromTime : start
        const windowEnd = isValidDate(toTime) ? toTime : new Date(now.getTime() + 365 * 86400000)

        let count = 0
        let t = new Date(start)

        if (windowStart > start) {
          const skipped = Math.floor((windowStart.getTime() - start.getTime()) / stepMs)
          if (skipped > 0) {
            count = skipped
            t = new Date(start.getTime() + skipped * stepMs)
          }

          while (t < windowStart) {
            t = new Date(t.getTime() + stepMs)
            count += 1
          }
        }

        while (true) {
          if (globalCount >= MAX_PROTOCOL_EVENTS) break
          if (occurrences != null && count >= occurrences) break
          if (until && isValidDate(until) && t > until) break
          if (t > windowEnd) break

          const isPast = t < now
          if ((isPast && includePast) || (!isPast && includeFuture)) {
            events.push({
              compound: compoundName,
              dose_mg: dose,
              time: iso(t),
              source: "protocol"
            })
            globalCount += 1
          }

          t = new Date(t.getTime() + stepMs)
          count += 1
        }
      }

      return events.sort(function(a, b) { return dt(a.time) - dt(b.time) })
    }

    function allEventsForCompound(data, compoundName, fromTime, toTime, options) {
      const logged = loggedEventsForCompound(data, compoundName, fromTime, toTime)
      const protocol = options && options.includeProtocols
        ? generateProtocolEvents(data, compoundName, fromTime, toTime, options.protocolOptions || {})
        : []
      return logged
        .concat(protocol)
        .sort(function(a, b) { return dt(a.time) - dt(b.time) })
    }

    function amountForCompoundAt(data, compoundName, t, options) {
      const compound = data.compounds[compoundName]
      if (!compound) return 0

      const halfLifeDays = Math.max(0.001, toNumber(compound.half_life_days, 1))
      const adaptiveLookbackDays = Math.min(3650, Math.max(HISTORY_LOOKBACK_DAYS, halfLifeDays * 20))
      const horizonStart = new Date(t.getTime() - adaptiveLookbackDays * 86400000)
      const events = allEventsForCompound(data, compoundName, horizonStart, t, options || {})
      let total = 0
      for (const event of events) total += eventAmountAtTime(event, t, compound)
      return total
    }

    function concentrationForCompoundAt(data, compoundName, t, options) {
      const compound = data.compounds[compoundName]
      if (!compound) return null
      const vd = Math.max(0.001, toNumber(compound.vd_l, 10))
      return amountForCompoundAt(data, compoundName, t, options) / vd
    }

    function nextScheduledDose(data, compoundName, fromTime) {
      const oneYearOut = new Date(fromTime.getTime() + 365 * 86400000)
      const future = generateProtocolEvents(data, compoundName, fromTime, oneYearOut, {
        includePast: false,
        includeFuture: true
      })
      return future.length ? future[0] : null
    }

    function confidenceMeta(quality) {
      return MODEL_CONFIDENCE[quality] || MODEL_CONFIDENCE.rough
    }

    function protocolOptionsForTime(referenceNow, evaluationTime) {
      const now = isValidDate(referenceNow) ? referenceNow : new Date()
      const evalTime = isValidDate(evaluationTime) ? evaluationTime : now
      return {
        includePast: true,
        includeFuture: evalTime > now
      }
    }

    function summaryRows(data) {
      const now = new Date()
      const names = activeCompoundNames(data)
      const rows = []
      const protocolOptions = protocolOptionsForTime(now, now)

      for (const name of names) {
        const compound = data.compounds[name]
        if (!compound) continue

        const amount = amountForCompoundAt(data, name, now, {
          includeProtocols: true,
          protocolOptions: protocolOptions
        })
        const concentration = concentrationForCompoundAt(data, name, now, {
          includeProtocols: true,
          protocolOptions: protocolOptions
        })
        const nextDose = nextScheduledDose(data, name, now)
        const lastDose = data.injections
          .filter(function(injection) { return injection.compound === name })
          .sort(function(a, b) { return dt(b.time) - dt(a.time) })[0] || null
        const confidence = confidenceMeta(compound.model_quality)

        rows.push({
          name: name,
          display_name: compound.display_name || titleCase(name),
          category: compound.category || DEFAULT_CATEGORY,
          color: compound.color,
          quality: compound.model_quality,
          quality_label: confidence.label,
          quality_badge: confidence.badge,
          route: compound.route || "unknown",
          amount: amount,
          concentration: concentration,
          last: lastDose,
          next: nextDose
        })
      }

      rows.sort(function(a, b) { return b.amount - a.amount })
      return rows
    }

    function buildSeries(data, selectedCompounds, daysBack, daysForward, mode) {
      const now = new Date()
      const start = new Date(now.getTime() - daysBack * 86400000)
      const end = new Date(now.getTime() + daysForward * 86400000)
      const spanDays = daysBack + daysForward
      let stepHours = 6
      if (spanDays <= 3) stepHours = 0.25
      else if (spanDays <= 14) stepHours = 0.5
      else if (spanDays <= 45) stepHours = 1
      else if (spanDays <= 120) stepHours = 3
      else if (spanDays <= 360) stepHours = 6
      else stepHours = 12
      const stepMs = stepHours * 3600000

      const dataset = {
        mode: mode,
        start: iso(start),
        end: iso(end),
        now: iso(now),
        compounds: []
      }

      for (const name of selectedCompounds) {
        const compound = data.compounds[name]
        if (!compound) continue

        const points = []
        for (let t = start.getTime(); t <= end.getTime(); t += stepMs) {
          const time = new Date(t)
          const protocolOptions = protocolOptionsForTime(now, time)
          let value = 0
          if (mode === "concentration") {
            value = concentrationForCompoundAt(data, name, time, {
              includeProtocols: true,
              protocolOptions: protocolOptions
            })
          } else {
            value = amountForCompoundAt(data, name, time, {
              includeProtocols: true,
              protocolOptions: protocolOptions
            })
          }
          points.push([iso(time), Number(Math.max(0, value || 0).toFixed(6))])
        }

        const markers = allEventsForCompound(data, name, start, end, {
          includeProtocols: true,
          protocolOptions: { includePast: true, includeFuture: true }
        })
          .map(function(event) {
            return [event.time, event.dose_mg, event.source]
          })

        dataset.compounds.push({
          name: name,
          display_name: compound.display_name || titleCase(name),
          color: compound.color,
          model_quality: compound.model_quality,
          route: compound.route,
          category: compound.category || DEFAULT_CATEGORY,
          points: points,
          markers: markers
        })
      }

      return dataset
    }

    function pushMergedInjection(data, compoundName, dose, timeIso, notes, source) {
      const compound = data.compounds[compoundName]
      data.injections.push({
        id: makeId("inj"),
        compound: compoundName,
        dose_mg: dose,
        time: timeIso,
        source: source || "log",
        notes: notes || "",
        category: compound.category,
        source_file: compound.source_file
      })
      data.injections.sort(function(a, b) { return dt(a.time) - dt(b.time) })
    }

    function pushMergedProtocol(data, compoundName, protocol) {
      const compound = data.compounds[compoundName]
      data.protocols.push({
        id: protocol.id,
        compound: compoundName,
        start: protocol.start,
        dose_mg: protocol.dose_mg,
        every_days: protocol.every_days,
        occurrences: protocol.occurrences,
        until: protocol.until,
        enabled: protocol.enabled,
        notes: protocol.notes || "",
        category: compound.category,
        source_file: compound.source_file
      })
      data.protocols.sort(function(a, b) { return dt(a.start) - dt(b.start) })
    }

    function addInjection(data, compoundName, doseMg, timeValue, notes) {
      const compound = data.compounds[compoundName]
      if (!compound) throw new Error("Unknown compound: " + compoundName)
      const dose = toNumber(doseMg, NaN)
      if (!Number.isFinite(dose) || dose <= 0) throw new Error("Dose must be a positive number")

      const time = new Date(timeValue || new Date())
      if (!isValidDate(time)) throw new Error("Invalid time")

      const fileState = data.__files[compound.source_file]
      if (!fileState) throw new Error("Unable to resolve history file for compound")

      fileState.history.injections.push({
        id: makeId("inj"),
        compound: compound.base_key,
        dose_mg: dose,
        time: iso(time),
        source: "log",
        notes: notes || ""
      })
      fileState.history.injections.sort(function(a, b) { return dt(a.time) - dt(b.time) })
      saveHistoryFile(compound.source_file, fileState.history)

      pushMergedInjection(data, compoundName, dose, iso(time), notes, "log")
    }

    function protocolHistoryRecord(compound, id, dose, start, everyDays, occurrences, until, enabled, notes) {
      return {
        id: id,
        compound: compound.base_key,
        dose_mg: dose,
        start: iso(start),
        every_days: everyDays,
        occurrences: occurrences,
        until: until && isValidDate(until) ? iso(until) : null,
        enabled: enabled !== false,
        notes: notes || ""
      }
    }

    function updateInjectionEntry(data, injectionId, compoundName, doseMg, timeValue, notes) {
      const id = String(injectionId || "").trim()
      if (!id) throw new Error("Missing injection id")

      const injectionIndex = data.injections.findIndex(function(injection) {
        return String(injection.id || "") === id
      })
      if (injectionIndex < 0) throw new Error("Injection not found: " + id)

      const existing = data.injections[injectionIndex]
      const existingCompound = data.compounds[existing.compound]
      const compound = data.compounds[compoundName]
      if (!compound) throw new Error("Unknown compound: " + compoundName)

      const dose = toNumber(doseMg, NaN)
      if (!Number.isFinite(dose) || dose <= 0) throw new Error("Dose must be a positive number")

      const time = new Date(timeValue || existing.time)
      if (!isValidDate(time)) throw new Error("Invalid time")

      const sourceFileName = existing.source_file || (existingCompound ? existingCompound.source_file : compound.source_file)
      const targetFileName = compound.source_file
      const sourceFileState = data.__files[sourceFileName]
      const targetFileState = data.__files[targetFileName]
      if (!sourceFileState || !targetFileState) throw new Error("Unable to resolve history file for injection update")

      const sourceIndex = sourceFileState.history.injections.findIndex(function(injection) {
        return String(injection.id || "") === id
      })
      if (sourceIndex < 0) throw new Error("Injection not found in history file: " + id)

      const updatedHistoryRecord = {
        id: id,
        compound: compound.base_key,
        dose_mg: dose,
        time: iso(time),
        source: existing.source || "log",
        notes: notes || ""
      }

      if (sourceFileName === targetFileName) {
        sourceFileState.history.injections[sourceIndex] = updatedHistoryRecord
        sourceFileState.history.injections.sort(function(a, b) { return dt(a.time) - dt(b.time) })
        saveHistoryFile(sourceFileName, sourceFileState.history)
      } else {
        sourceFileState.history.injections.splice(sourceIndex, 1)
        targetFileState.history.injections.push(updatedHistoryRecord)

        sourceFileState.history.injections.sort(function(a, b) { return dt(a.time) - dt(b.time) })
        targetFileState.history.injections.sort(function(a, b) { return dt(a.time) - dt(b.time) })

        saveHistoryFile(sourceFileName, sourceFileState.history)
        saveHistoryFile(targetFileName, targetFileState.history)
      }

      data.injections[injectionIndex] = {
        id: id,
        compound: compoundName,
        dose_mg: dose,
        time: iso(time),
        source: existing.source || "log",
        notes: notes || "",
        category: compound.category,
        source_file: targetFileName
      }
      data.injections.sort(function(a, b) { return dt(a.time) - dt(b.time) })
    }

    function removeInjectionEntry(data, injectionId) {
      const id = String(injectionId || "").trim()
      if (!id) throw new Error("Missing injection id")

      const injectionIndex = data.injections.findIndex(function(injection) {
        return String(injection.id || "") === id
      })
      if (injectionIndex < 0) throw new Error("Injection not found: " + id)

      const existing = data.injections[injectionIndex]
      const existingCompound = data.compounds[existing.compound]
      const fallbackFile = existingCompound ? existingCompound.source_file : null
      const expectedFile = existing.source_file || fallbackFile

      let sourceFileName = null
      if (expectedFile && data.__files[expectedFile]) {
        const directIndex = data.__files[expectedFile].history.injections.findIndex(function(injection) {
          return String(injection.id || "") === id
        })
        if (directIndex >= 0) sourceFileName = expectedFile
      }

      if (!sourceFileName) {
        const fileNames = Object.keys(data.__files)
        for (const fileName of fileNames) {
          const state = data.__files[fileName]
          const idx = state.history.injections.findIndex(function(injection) {
            return String(injection.id || "") === id
          })
          if (idx >= 0) {
            sourceFileName = fileName
            break
          }
        }
      }

      if (!sourceFileName) throw new Error("Injection not found in history files: " + id)

      const sourceFileState = data.__files[sourceFileName]
      const sourceIndex = sourceFileState.history.injections.findIndex(function(injection) {
        return String(injection.id || "") === id
      })
      if (sourceIndex < 0) throw new Error("Injection not found in history file: " + id)

      sourceFileState.history.injections.splice(sourceIndex, 1)
      sourceFileState.history.injections.sort(function(a, b) { return dt(a.time) - dt(b.time) })
      saveHistoryFile(sourceFileName, sourceFileState.history)

      data.injections.splice(injectionIndex, 1)
      data.injections.sort(function(a, b) { return dt(a.time) - dt(b.time) })

      return {
        id: id,
        source_file: sourceFileName,
        compound: existing.compound
      }
    }

    function addProtocolEntry(data, entry) {
      const compoundName = normalizeCompoundKey(data, entry.compound, entry.category)
      if (!compoundName) throw new Error("Unknown compound: " + entry.compound)

      const compound = data.compounds[compoundName]
      const fileState = data.__files[compound.source_file]
      if (!fileState) throw new Error("Unable to resolve history file for compound")

      const start = new Date(entry.start || new Date())
      const dose = toNumber(entry.dose_mg != null ? entry.dose_mg : entry.dose, NaN)
      const everyDays = toNumber(entry.every_days, 7)
      if (!isValidDate(start) || !Number.isFinite(dose) || dose <= 0 || !Number.isFinite(everyDays) || everyDays <= 0) {
        throw new Error("Protocol entry is invalid")
      }

      const occurrences = entry.occurrences != null && entry.occurrences !== ""
        ? Math.max(0, Math.floor(toNumber(entry.occurrences, 0)))
        : null
      const until = entry.until ? new Date(entry.until) : null
      const protocol = protocolHistoryRecord(
        compound,
        makeId("pro"),
        dose,
        start,
        everyDays,
        occurrences,
        until,
        entry.enabled !== false,
        entry.notes || ""
      )

      fileState.history.protocols.push(protocol)
      fileState.history.protocols.sort(function(a, b) { return dt(a.start) - dt(b.start) })
      saveHistoryFile(compound.source_file, fileState.history)

      pushMergedProtocol(data, compoundName, protocol)
    }

    function updateProtocolEntry(data, protocolId, entry) {
      const id = normalizeText(protocolId)
      if (!id) throw new Error("Missing protocol id")

      const protocolIndex = data.protocols.findIndex(function(protocol) {
        return normalizeText(protocol.id) === id
      })
      if (protocolIndex < 0) throw new Error("Protocol not found: " + id)

      const existing = data.protocols[protocolIndex]
      const existingCompound = data.compounds[existing.compound]
      const compoundName = normalizeCompoundKey(data, entry.compound != null ? entry.compound : existing.compound, entry.category || existing.category)
      if (!compoundName) throw new Error("Unknown compound: " + (entry.compound != null ? entry.compound : existing.compound))
      const compound = data.compounds[compoundName]
      const start = new Date(entry.start || existing.start)
      const dose = toNumber(entry.dose_mg != null ? entry.dose_mg : entry.dose != null ? entry.dose : existing.dose_mg, NaN)
      const everyDays = toNumber(entry.every_days != null ? entry.every_days : existing.every_days, NaN)
      const occurrences = entry.occurrences != null && entry.occurrences !== ""
        ? Math.max(0, Math.floor(toNumber(entry.occurrences, 0)))
        : (entry.occurrences === "" ? null : existing.occurrences)
      const until = entry.until ? new Date(entry.until) : (entry.until === "" ? null : (existing.until ? new Date(existing.until) : null))
      const enabled = typeof entry.enabled === "boolean" ? entry.enabled : existing.enabled !== false
      if (!isValidDate(start) || !Number.isFinite(dose) || dose <= 0 || !Number.isFinite(everyDays) || everyDays <= 0) {
        throw new Error("Protocol entry is invalid")
      }

      const sourceFileName = existing.source_file || (existingCompound ? existingCompound.source_file : compound.source_file)
      const targetFileName = compound.source_file
      const sourceFileState = data.__files[sourceFileName]
      const targetFileState = data.__files[targetFileName]
      if (!sourceFileState || !targetFileState) throw new Error("Unable to resolve history file for protocol update")

      const sourceIndex = sourceFileState.history.protocols.findIndex(function(protocol) {
        return normalizeText(protocol.id) === id
      })
      if (sourceIndex < 0) throw new Error("Protocol not found in history file: " + id)

      const updatedHistoryRecord = protocolHistoryRecord(compound, id, dose, start, everyDays, occurrences, until, enabled, entry.notes != null ? entry.notes : existing.notes || "")

      if (sourceFileName === targetFileName) {
        sourceFileState.history.protocols[sourceIndex] = updatedHistoryRecord
        sourceFileState.history.protocols.sort(function(a, b) { return dt(a.start) - dt(b.start) })
        saveHistoryFile(sourceFileName, sourceFileState.history)
      } else {
        sourceFileState.history.protocols.splice(sourceIndex, 1)
        targetFileState.history.protocols.push(updatedHistoryRecord)
        sourceFileState.history.protocols.sort(function(a, b) { return dt(a.start) - dt(b.start) })
        targetFileState.history.protocols.sort(function(a, b) { return dt(a.start) - dt(b.start) })
        saveHistoryFile(sourceFileName, sourceFileState.history)
        saveHistoryFile(targetFileName, targetFileState.history)
      }

      data.protocols[protocolIndex] = {
        id: id,
        compound: compoundName,
        start: updatedHistoryRecord.start,
        dose_mg: updatedHistoryRecord.dose_mg,
        every_days: updatedHistoryRecord.every_days,
        occurrences: updatedHistoryRecord.occurrences,
        until: updatedHistoryRecord.until,
        enabled: updatedHistoryRecord.enabled,
        notes: updatedHistoryRecord.notes,
        category: compound.category,
        source_file: targetFileName
      }
      data.protocols.sort(function(a, b) { return dt(a.start) - dt(b.start) })
    }

    function removeProtocolEntry(data, protocolId) {
      const id = normalizeText(protocolId)
      if (!id) throw new Error("Missing protocol id")
      const protocolIndex = data.protocols.findIndex(function(protocol) {
        return normalizeText(protocol.id) === id
      })
      if (protocolIndex < 0) throw new Error("Protocol not found: " + id)

      const existing = data.protocols[protocolIndex]
      const expectedFile = existing.source_file
      const fileState = expectedFile ? data.__files[expectedFile] : null
      if (!fileState) throw new Error("Unable to resolve history file for protocol delete")

      const sourceIndex = fileState.history.protocols.findIndex(function(protocol) {
        return normalizeText(protocol.id) === id
      })
      if (sourceIndex < 0) throw new Error("Protocol not found in history file: " + id)

      fileState.history.protocols.splice(sourceIndex, 1)
      fileState.history.protocols.sort(function(a, b) { return dt(a.start) - dt(b.start) })
      saveHistoryFile(expectedFile, fileState.history)

      data.protocols.splice(protocolIndex, 1)
      data.protocols.sort(function(a, b) { return dt(a.start) - dt(b.start) })
      return existing
    }

    function toggleProtocolEntry(data, protocolId, enabled) {
      updateProtocolEntry(data, protocolId, { enabled: enabled })
    }

// ---------- Widget UI ----------
function widgetModeFromArgs() {
  const raw = normalizeText(args.widgetParameter || "")
  if (!raw) return "top"
  const mode = raw.toLowerCase()
  if (mode === "next" || mode === "today" || mode === "top") return mode
  return "top"
}

function makeWidget(data) {
  const now = new Date()
  const rows = summaryRows(data).slice(0, 3)
  const mode = widgetModeFromArgs()

  const w = new ListWidget()
  const gradient = new LinearGradient()
  gradient.colors = [new Color("#081326"), new Color("#121a2e")]
  gradient.locations = [0, 1]
  w.backgroundGradient = gradient
  w.setPadding(14, 14, 14, 14)

  const title = w.addText(APP_NAME)
  title.textColor = Color.white()
  title.font = Font.boldSystemFont(16)

  const subtitle = w.addText("Approximate tracking dashboard")
  subtitle.textColor = new Color("#9FB1CC")
  subtitle.font = Font.systemFont(10)
  w.addSpacer(8)

  if (mode === "today") {
    const todayCutoff = new Date(now.getTime() - 86400000)
    const recent = data.injections
      .filter(function(injection) {
        const at = dt(injection.time)
        return isValidDate(at) && at >= todayCutoff
      })
      .slice(-3)

    const heading = w.addText("Last 24 hours")
    heading.textColor = Color.white()
    heading.font = Font.semiboldSystemFont(12)
    w.addSpacer(4)

    if (!recent.length) {
      const emptyToday = w.addText("No injections logged in the last day")
      emptyToday.textColor = new Color("#CBD5E1")
      emptyToday.font = Font.systemFont(11)
    } else {
      for (const injection of recent.reverse()) {
        const compound = data.compounds[injection.compound] || {}
        const item = w.addText(`${compound.display_name || injection.compound} ${Number(injection.dose_mg).toFixed(2)} mg`)
        item.textColor = new Color("#DCE7F5")
        item.font = Font.systemFont(11)
      }
    }

    w.addSpacer(8)
    const footerToday = w.addText(formatDateTime(now))
    footerToday.textColor = new Color("#64748B")
    footerToday.font = Font.systemFont(9)
    return w
  }

  if (mode === "next") {
    const upcoming = summaryRows(data)
      .map(function(row) {
        return row.next ? { row: row, nextAt: dt(row.next.time) } : null
      })
      .filter(function(value) { return value && isValidDate(value.nextAt) })
      .sort(function(a, b) { return a.nextAt - b.nextAt })
      .slice(0, 3)

    const heading = w.addText("Next scheduled doses")
    heading.textColor = Color.white()
    heading.font = Font.semiboldSystemFont(12)
    w.addSpacer(4)

    if (!upcoming.length) {
      const emptyNext = w.addText("No enabled schedules")
      emptyNext.textColor = new Color("#CBD5E1")
      emptyNext.font = Font.systemFont(11)
    } else {
      for (const item of upcoming) {
        const line = w.addText(`${item.row.display_name} ${formatRelativeTime(item.nextAt, now)}`)
        line.textColor = new Color(item.row.color)
        line.font = Font.systemFont(11)
      }
    }

    w.addSpacer(8)
    const footerNext = w.addText(formatDateTime(now))
    footerNext.textColor = new Color("#64748B")
    footerNext.font = Font.systemFont(9)
    return w
  }

  if (!rows.length) {
    const empty = w.addText("No injections logged yet")
    empty.textColor = new Color("#CBD5E1")
    empty.font = Font.systemFont(12)

    const tip = w.addText("Use the Log Injection shortcut to get started")
    tip.textColor = new Color("#94A3B8")
    tip.font = Font.systemFont(10)
    return w
  }

  for (const row of rows) {
    const stack = w.addStack()
    stack.layoutVertically()

    const line1 = stack.addStack()
    const dot = line1.addText("● ")
    dot.textColor = new Color(row.color)
    dot.font = Font.boldSystemFont(12)

    const name = line1.addText(row.display_name)
    name.textColor = Color.white()
    name.font = Font.semiboldSystemFont(12)

    const amounts = stack.addText(`${row.amount.toFixed(2)} mg • ${row.concentration.toFixed(3)} mg/L`)
    amounts.textColor = new Color("#CBD5E1")
    amounts.font = Font.systemFont(11)

    const quality = stack.addText(row.quality_label)
    quality.textColor = row.quality_badge === "good" ? new Color("#86EFAC") : (row.quality_badge === "low" ? new Color("#FCA5A5") : new Color("#FDE68A"))
    quality.font = Font.systemFont(10)

    if (row.next) {
      const when = dt(row.next.time)
      const next = stack.addText(`Next ${formatRelativeTime(when, now)} (${formatShortDateTime(when)})`)
      next.textColor = new Color("#94A3B8")
      next.font = Font.systemFont(10)
    }

    w.addSpacer(6)
  }

  const footer = w.addText(formatDateTime(now))
  footer.textColor = new Color("#64748B")
  footer.font = Font.systemFont(9)
  return w
}

// ---------- Dashboard HTML ----------
const DASHBOARD_DATASET_WINDOWS = [1, 7, 30, 90, 180, 365]

function buildDashboardDatasets(data, defaults) {
  const datasets = {}
  for (const mode of ["amount", "concentration"]) {
    for (const days of DASHBOARD_DATASET_WINDOWS) {
      datasets[`${mode}_${days}`] = buildSeries(data, defaults, days, days, mode)
    }
  }
  return datasets
}

function buildDashboardPayload(data, rows) {
  const defaults = activeCompoundNames(data)
  const nextScheduledAt = rows
    .map(function(row) { return row.next ? dt(row.next.time) : null })
    .filter(function(value) { return isValidDate(value) })
    .sort(function(a, b) { return a - b })[0] || null

  return {
    schema_version: data.schema_version,
    overview: {
      compound_count: compoundNames(data).length,
      active_compound_count: defaults.length,
      injection_count: data.injections.length,
      recent_injection_count: data.injections.filter(function(injection) {
        const at = dt(injection.time)
        return isValidDate(at) && daysBetween(at, new Date()) <= 7
      }).length,
      enabled_schedule_count: data.protocols.filter(function(protocol) { return protocol.enabled !== false }).length,
      next_scheduled_at: nextScheduledAt ? iso(nextScheduledAt) : null
    },
    diagnostics: {
      warnings: data.__diagnostics && Array.isArray(data.__diagnostics.warnings) ? data.__diagnostics.warnings.slice(0, 8) : []
    },
    recent_compounds: data.injections
      .slice()
      .sort(function(a, b) { return dt(b.time) - dt(a.time) })
      .map(function(injection) { return injection.compound })
      .filter(function(value, index, list) { return list.indexOf(value) === index })
      .slice(0, 4),
    compounds: compoundNames(data).map(function(name) {
      const c = data.compounds[name]
      return {
        name: name,
        display_name: c.display_name || titleCase(name),
        category: c.category || DEFAULT_CATEGORY,
        color: c.color,
        quality: c.model_quality || "rough",
        route: c.route || "unknown",
        notes: c.notes || "",
        provenance: c.provenance || "Unspecified",
        references: Array.isArray(c.references) ? c.references.slice() : []
      }
    }),
    rows: rows.map(function(r) {
      return {
        name: r.name,
        display_name: r.display_name,
        category: r.category || DEFAULT_CATEGORY,
        color: r.color,
        quality: r.quality,
        quality_label: r.quality_label,
        route: r.route,
        amount: Number(r.amount.toFixed(3)),
        concentration: Number(r.concentration.toFixed(4)),
        last: r.last ? { dose_mg: r.last.dose_mg, time: r.last.time } : null,
        next: r.next ? r.next.time : null
      }
    }),
    injection_history: data.injections
      .slice()
      .sort(function(a, b) { return dt(b.time) - dt(a.time) })
      .slice(0, 300)
      .map(function(injection) {
        const compound = data.compounds[injection.compound] || {}
        return {
          id: injection.id,
          compound: injection.compound,
          display_name: compound.display_name || titleCase(injection.compound),
          category: compound.category || injection.category || DEFAULT_CATEGORY,
          route: compound.route || "unknown",
          quality: compound.model_quality || "rough",
          dose_mg: toNumber(injection.dose_mg, 0),
          time: injection.time,
          source: injection.source || "log",
          notes: injection.notes || ""
        }
      }),
    protocols: data.protocols
      .slice()
      .sort(function(a, b) { return dt(a.start) - dt(b.start) })
      .slice(0, 60)
      .map(function(protocol) {
        const compound = data.compounds[protocol.compound] || {}
        return {
          id: protocol.id,
          compound: protocol.compound,
          display_name: compound.display_name || titleCase(protocol.compound),
          category: compound.category || protocol.category || DEFAULT_CATEGORY,
          color: compound.color || "#9fb1cc",
          quality: compound.model_quality || "rough",
          route: compound.route || "unknown",
          provenance: compound.provenance || "Unspecified",
          dose_mg: toNumber(protocol.dose_mg, 0),
          every_days: toNumber(protocol.every_days, 0),
          occurrences: protocol.occurrences,
          start: protocol.start,
          until: protocol.until,
          enabled: protocol.enabled !== false,
          notes: protocol.notes || ""
        }
      }),
    datasets: buildDashboardDatasets(data, defaults)
  }
}

function dashboardHTML(data, rows) {
  const payload = JSON.stringify(buildDashboardPayload(data, rows))
  return renderDashboardHTML(APP_NAME, payload)
}

function escapeHtml(s) {
  return String(s)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/\"/g, "&quot;")
}

